 @property {boolean} [reflect]\n * @property {'String'|'Boolean'|'Number'|'Array'|'Object'} [type]\n */\n","<script>\r\n    let username = '';\r\n    let password = '';\r\n    let errorMessage = '';\r\n\r\n    async function handleLogin(event) {\r\n        event.preventDefault();\r\n        errorMessage = '';\r\n        \r\n        try {\r\n            const response = await fetch('/api/v1/login', {\r\n                method: 'POST',\r\n                headers: {\r\n                    'Content-Type': 'application/json'\r\n                },\r\n                body: JSON.stringify({ userid: username, password: password })\r\n            });\r\n\r\n            // Use vanilla window.location.href for clean URL navigation\r\n            if (response.ok) {\r\n                window.location.href = '/dashboard';\r\n            } else {\r\n                const data = await response.json();\r\n                errorMessage = data.error || 'Login failed (Bad Credentials)';\r\n            }\r\n        } catch (error) {\r\n            console.error('Error:', error);\r\n            errorMessage = 'A network error occurred.';\r\n        }\r\n    }\r\n</script>\r\n\r\n<main class=\"login-container\">\r\n    <div class=\"card\">\r\n        <h1>Watt-Watch</h1>\r\n        <p>Please log in to your account.</p>\r\n        \r\n        {#if errorMessage}\r\n            <div class=\"error-message\">{errorMessage}</div>\r\n        {/if}\r\n\r\n        <form on:submit={handleLogin}>\r\n            <div class=\"input-group\">\r\n                <label for=\"username\">Username</label>\r\n                <input \r\n                    type=\"text\" \r\n                    id=\"username\" \r\n                    bind:value={username} \r\n                    placeholder=\"Enter your username\" \r\n                    required \r\n                />\r\n            </div>\r\n            \r\n            <div class=\"input-group\">\r\n                <label for=\"password\">Password</label>\r\n                <input \r\n                    type=\"password\" \r\n                    id=\"password\" \r\n                    bind:value={password} \r\n                    placeholder=\"Enter your password\" \r\n                    required \r\n                />\r\n            </div>\r\n\r\n            <button type=\"submit\">Sign In</button>\r\n        </form>\r\n    </div>\r\n</main>\r\n\r\n<style>\r\n    :global(body) {\r\n        margin: 0;\r\n        font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\r\n        background-color: #0f111a;\r\n        color: white;\r\n    }\r\n\r\n    .login-container {\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        height: 100vh;\r\n    }\r\n\r\n    .card {\r\n        background: #1a1d27;\r\n        padding: 40px;\r\n        border-radius: 12px;\r\n        text-align: center;\r\n        box-shadow: 0 8px 16px rgba(0, 0, 0, 0.4);\r\n        width: 100%;\r\n        max-width: 380px;\r\n    }\r\n\r\n    .error-message {\r\n        background-color: rgba(255, 85, 85, 0.1);\r\n        color: #ff5555;\r\n        border: 1px solid #ff5555;\r\n        padding: 10px;\r\n        border-radius: 6px;\r\n        margin-bottom: 20px;\r\n        font-size: 14px;\r\n        text-align: left;\r\n    }\r\n\r\n    h1 {\r\n        margin-top: 0;\r\n        color: #50fa7b;\r\n        margin-bottom: 10px;\r\n    }\r\n\r\n    p {\r\n        color: #a8a8b3;\r\n        margin-bottom: 30px;\r\n    }\r\n\r\n    form {\r\n        display: flex;\r\n        flex-direction: column;\r\n        text-align: left;\r\n    }\r\n\r\n    .input-group {\r\n        margin-bottom: 20px;\r\n    }\r\n\r\n    label {\r\n        display: block;\r\n        margin-bottom: 8px;\r\n        font-size: 14px;\r\n        color: #e6e6e6;\r\n        font-weight: 500;\r\n    }\r\n\r\n    input {\r\n        width: 100%;\r\n        padding: 12px;\r\n        border-radius: 6px;\r\n        border: 1px solid #333;\r\n        background-color: #0f111a;\r\n        color: white;\r\n        font-size: 16px;\r\n        box-sizing: border-box;\r\n        transition: border-color 0.2s, box-shadow 0.2s;\r\n    }\r\n\r\n    input::placeholder {\r\n        color: #4a4a55;\r\n    }\r\n\r\n    input:focus {\r\n        border-color: #50fa7b;\r\n        outline: none;\r\n        box-shadow: 0 0 0 2px rgba(80, 250, 123, 0.2);\r\n    }\r\n\r\n    button {\r\n        background: #50fa7b;\r\n        color: #0f111a;\r\n        border: none;\r\n        padding: 14px;\r\n        border-radius: 6px;\r\n        font-weight: bold;\r\n        font-size: 16px;\r\n        cursor: pointer;\r\n        transition: opacity 0.2s, transform 0.1s;\r\n        margin-top: 10px;\r\n    }\r\n\r\n    button:hover {\r\n        opacity: 0.9;\r\n    }\r\n\r\n    button:active {\r\n        transform: translateY(1px);\r\n    }\r\n</style>\r\n","import { PUBLIC_VERSION } from '../../../shared/version.js';\n\nif (typeof window !== 'undefined')\n\t// @ts-ignore\n\t(window.__svelte || (window.__svelte = { v: new Set() })).v.add(PUBLIC_VERSION);\n","// generated during release, do not modify\n\n/**\n * The current version, as set in package.json.\n *\n * https://svelte.dev/docs/svelte-compiler#svelte-version\n * @type {string}\n */\nexport const VERSION = '4.2.19';\nexport const PUBLIC_VERSION = '4';\n","<script>\n    export let active = 'dashboard';\n    export let currentUser = null;\n\n    function handleLogout() {\n        window.location.href = '/logout';\n    }\n\n    const navItems = [\n        { id: 'dashboard', label: 'Dashboard', icon: '📊', href: '/dashboard' },\n        { id: 'rooms',     label: 'Rooms',     icon: '🏠', href: '/rooms'     },\n        { id: 'report',    label: 'Report',    icon: '📄', href: '/report'    },\n    ];\n</script>\n\n<nav class=\"sidebar\">\n    <div class=\"logo\">\n        <span class=\"bolt\">⚡</span>\n        <span class=\"logo-text\">Watt-Watch</span>\n    </div>\n\n    <div class=\"nav-links\">\n        {#each navItems as item}\n            <a\n                href={item.href}\n                class=\"nav-item\"\n                class:active={active === item.id}\n                id=\"nav-{item.id}\"\n            >\n                <span class=\"nav-icon\">{item.icon}</span>\n                <span class=\"nav-label\">{item.label}</span>\n                {#if active === item.id}\n                    <span class=\"active-pip\"></span>\n                {/if}\n            </a>\n        {/each}\n    </div>\n\n    <div class=\"spacer\"></div>\n\n    <button class=\"nav-item logout-btn\" on:click={handleLogout} id=\"nav-logout\">\n        <span class=\"nav-icon\">🚪</span>\n        <span class=\"nav-label\">Logout</span>\n    </button>\n\n    {#if currentUser}\n        <div class=\"user-profile\">\n            <div class=\"avatar\">{currentUser.userid[0].toUpperCase()}</div>\n            <div class=\"user-meta\">\n                <span class=\"username\">{currentUser.userid}</span>\n                <span class=\"role\">{currentUser.type.toUpperCase()}</span>\n            </div>\n        </div>\n    {/if}\n</nav>\n\n<style>\n    .sidebar {\n        width: 240px;\n        min-width: 240px;\n        background: rgba(10, 12, 20, 0.97);\n        border-right: 1px solid rgba(255, 255, 255, 0.04);\n        display: flex;\n        flex-direction: column;\n        padding: 1.8rem 1.2rem;\n        gap: 0.3rem;\n        height: 100vh;\n        box-sizing: border-box;\n    }\n\n    .logo {\n        display: flex;\n        align-items: center;\n        gap: 10px;\n        margin-bottom: 2.5rem;\n        padding-left: 0.4rem;\n    }\n\n    .bolt {\n        font-size: 1.4rem;\n        background: linear-gradient(135deg, #50fa7b, #8be9fd);\n        -webkit-background-clip: text;\n        background-clip: text;\n        -webkit-text-fill-color: transparent;\n    }\n\n    .logo-text {\n        font-size: 1.25rem;\n        font-weight: 700;\n        letter-spacing: -0.5px;\n        color: #f8fafc;\n    }\n\n    .nav-links {\n        display: flex;\n        flex-direction: column;\n        gap: 4px;\n    }\n\n    .nav-item {\n        display: flex;\n        align-items: center;\n        gap: 12px;\n        padding: 11px 14px;\n        text-decoration: none;\n        color: #64748b;\n        border-radius: 12px;\n        transition: all 0.2s ease;\n        position: relative;\n        font-size: 0.92rem;\n        font-weight: 500;\n        cursor: pointer;\n        border: none;\n        background: transparent;\n        font-family: inherit;\n        width: 100%;\n        text-align: left;\n    }\n\n    .nav-item:hover {\n        background: rgba(80, 250, 123, 0.07);\n        color: #e2e8f0;\n    }\n\n    .nav-item.active {\n        background: rgba(80, 250, 123, 0.12);\n        color: #50fa7b;\n    }\n\n    .nav-icon {\n        font-size: 1rem;\n        width: 20px;\n        text-align: center;\n    }\n\n    .active-pip {\n        width: 5px;\n        height: 5px;\n        border-radius: 50%;\n        background: #50fa7b;\n        box-shadow: 0 0 8px #50fa7b;\n        margin-left: auto;\n    }\n\n    .logout-btn {\n        color: #64748b;\n        margin-bottom: 0.5rem;\n    }\n\n    .logout-btn:hover {\n        background: rgba(255, 85, 85, 0.1);\n        color: #ff5555;\n    }\n\n    .spacer { flex: 1; }\n\n    .user-profile {\n        background: rgba(255, 255, 255, 0.03);\n        border: 1px solid rgba(255, 255, 255, 0.04);\n        padding: 0.9rem 1rem;\n        border-radius: 14px;\n        display: flex;\n        align-items: center;\n        gap: 10px;\n        margin-top: 0.5rem;\n    }\n\n    .avatar {\n        width: 36px;\n        height: 36px;\n        background: linear-gradient(135deg, #bd93f9, #ff79c6);\n        border-radius: 10px;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        font-weight: 700;\n        font-size: 0.9rem;\n        color: #fff;\n        flex-shrink: 0;\n    }\n\n    .user-meta {\n        display: flex;\n        flex-direction: column;\n        overflow: hidden;\n    }\n\n    .username {\n        font-weight: 600;\n        font-size: 0.85rem;\n        color: #e2e8f0;\n        white-space: nowrap;\n        overflow: hidden;\n        text-overflow: ellipsis;\n    }\n\n    .role {\n        font-size: 0.65rem;\n        color: #50fa7b;\n        font-weight: 700;\n        letter-spacing: 0.5px;\n    }\n</style>\n","<script>\r\n    import { onMount, onDestroy } from 'svelte';\r\n    import Sidebar from '../components/Sidebar.svelte';\r\n\r\n    let currentUser = null;\r\n    let errorMessage = '';\r\n    let loading = true;\r\n    let redacted = true;\r\n    let timeStr = '';\r\n    let clockInterval;\r\n    let pollInterval;\r\n    let isRefreshing = false;\r\n\r\n    let stats = { totalRooms: 0, wasteKw: 0, totalKw: 0 };\r\n    let rooms = [];\r\n    let selectedRoom = null;\r\n\r\n    let alerts = [];\r\n\r\n    function tick() {\r\n        timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });\r\n    }\r\n\r\n    async function fetchLiveData() {\r\n        try {\r\n            isRefreshing = true;\r\n            const [statsRes, roomsRes, alertsRes] = await Promise.all([\r\n                fetch('/api/v1/stats'),\r\n                fetch('/api/v1/room_list/'),\r\n                fetch('/api/v1/alerts'),\r\n            ]);\r\n            if (statsRes.ok)  stats = await statsRes.json();\r\n            if (roomsRes.ok) {\r\n                const data = await roomsRes.json();\r\n                rooms = data.rooms || [];\r\n                stats.totalRooms = rooms.length;\r\n\r\n                if (selectedRoom) {\r\n                    selectedRoom = rooms.find(r => String(r.room_id) === String(selectedRoom.room_id)) || selectedRoom;\r\n                }\r\n            }\r\n            if (alertsRes.ok) {\r\n                const data = await alertsRes.json();\r\n                alerts = data.alerts || [];\r\n            }\r\n        } catch (e) {\r\n            console.error('Poll error', e);\r\n        } finally {\r\n            setTimeout(() => { isRefreshing = false; }, 1000);\r\n        }\r\n    }\r\n\r\n    onMount(async () => {\r\n        tick();\r\n        clockInterval = setInterval(tick, 1000);\r\n\r\n        try {\r\n            const authRes = await fetch('/api/v1/auth/status');\r\n            if (!authRes.ok) { window.location.href = '/login'; return; }\r\n            currentUser = await authRes.json();\r\n\r\n            const [statsRes, roomsRes, alertsRes] = await Promise.all([\r\n                fetch('/api/v1/stats'),\r\n                fetch('/api/v1/room_list/'),\r\n                fetch('/api/v1/alerts'),\r\n            ]);\r\n            if (statsRes.ok)  stats = await statsRes.json();\r\n            if (roomsRes.ok) {\r\n                const data = await roomsRes.json();\r\n                rooms = data.rooms || [];\r\n                stats.totalRooms = rooms.length;\r\n\r\n                // Check if a specific room was requested via ?room=N (from \"View Feed\" button)\r\n                const params = new URLSearchParams(window.location.search);\r\n                const requestedRoomId = params.get('room');\r\n                if (requestedRoomId) {\r\n                    selectedRoom = rooms.find(r => String(r.room_id) === String(requestedRoomId)) || null;\r\n                }\r\n                // If none requested (or not found), auto-select first room with a camera\r\n                if (!selectedRoom) {\r\n                    selectedRoom = rooms.find(r => r.ip && r.port) || rooms[0] || null;\r\n                }\r\n            }\r\n            if (alertsRes.ok) {\r\n                const data = await alertsRes.json();\r\n                alerts = data.alerts || [];\r\n            }\r\n            pollInterval = setInterval(fetchLiveData, 5000);\r\n        } catch (e) {\r\n            console.error('Dashboard init error', e);\r\n            errorMessage = 'Failed to connect to server';\r\n        } finally {\r\n            loading = false;\r\n        }\r\n    });\r\n\r\n    onDestroy(() => {\r\n        clearInterval(clockInterval);\r\n        clearInterval(pollInterval);\r\n    });\r\n\r\n    function selectRoom(room) {\r\n        selectedRoom = room;\r\n        redacted = true; // reset redact mode on room switch\r\n    }\r\n\r\n    $: cameraConnected = selectedRoom && selectedRoom.ip && selectedRoom.port;\r\n    $: videoSrc = cameraConnected\r\n        ? (redacted\r\n            ? `http://127.0.0.1:5000/video/${selectedRoom.ip}/${selectedRoom.port}/`\r\n            : `http://127.0.0.1:5000/video/${selectedRoom.ip}/${selectedRoom.port}/admin`)\r\n        : null;\r\n\r\n    function statusColor(s = '') {\r\n        const v = s.toLowerCase();\r\n        if (v === 'occupied') return '#50fa7b';\r\n        if (v === 'vacant')   return '#6272a4';\r\n        return '#ffb86c'; \r\n    }\r\n</script>\r\n\r\n<div class=\"dashboard-wrapper\">\r\n    <Sidebar active=\"dashboard\" {currentUser} />\r\n\r\n    <div class=\"main-content\">\r\n        {#if loading}\r\n            <div class=\"loader-wrap\">\r\n                <div class=\"loader\"></div>\r\n                <p>Initializing Watt-Watch…</p>\r\n            </div>\r\n        {:else}\r\n            <header class=\"page-header\">\r\n                <div>\r\n                    <h1>Energy Intelligence Dashboard</h1>\r\n                    <p class=\"subtitle\">Real-time surveillance &amp; consumption tracking</p>\r\n                </div>\r\n                <div class=\"header-right\">\r\n                    <div class=\"live-badge\"><span class=\"dot-live\"></span>System Live</div>\r\n                    {#if isRefreshing}\r\n                        <div style=\"font-size: 0.75rem; color: #50fa7b; margin-top: 6px; text-align: right; font-weight: 600;\">🔄 Refreshing data...</div>\r\n                    {/if}\r\n                </div>\r\n            </header>\r\n\r\n            <div class=\"top-stats\">\r\n                <div class=\"stat-card glass\" id=\"stat-rooms\">\r\n                    <span class=\"stat-label\">Total Rooms</span>\r\n                    <strong class=\"stat-val\">{stats.totalRooms}</strong>\r\n                </div>\r\n                <div class=\"stat-card glass\" id=\"stat-waste\">\r\n                    <span class=\"stat-label\">Waste Detected</span>\r\n                    <strong class=\"stat-val warning\">{stats.wasteKw} <small>kW</small></strong>\r\n                </div>\r\n\r\n\r\n            </div>\r\n\r\n            <div class=\"dashboard-grid\">\r\n\r\n                <div class=\"card glass cctv-card\">\r\n                    <div class=\"card-header\">\r\n                        <h3>CCTV Live Stream</h3>\r\n                        <div class=\"cctv-actions\">\r\n                            {#if currentUser?.type === 'admin'}\r\n                                <button\r\n                                    id=\"btn-redact-toggle\"\r\n                                    class=\"btn-pill\"\r\n                                    class:is-raw={!redacted}\r\n                                    on:click={() => redacted = !redacted}\r\n                                >\r\n                                    {redacted ? '🔓 SHOW RAW' : '🔒 REDACT'}\r\n                                </button>\r\n                            {/if}\r\n                            <span class=\"badge-rec\">● REC</span>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"video-wrap\">\r\n                        {#if cameraConnected}\r\n                            <img\r\n                                id=\"cctv-feed\"\r\n                                src={videoSrc}\r\n                                alt=\"CCTV Feed\"\r\n                                class=\"cctv-feed\"\r\n                                on:error={(e) => e.target.src =\r\n                                    'https://placehold.co/640x360/090b10/50fa7b?text=Searching+for+Camera+Signal...'}\r\n                            />\r\n                        {:else}\r\n                            <div class=\"no-camera\">\r\n                                <span class=\"no-cam-icon\">📷</span>\r\n                                <span class=\"no-cam-text\">Camera Not Connected</span>\r\n                                <span class=\"no-cam-sub\">{selectedRoom ? `Room ${selectedRoom.room_id} — no IP/port configured` : 'No room selected'}</span>\r\n                            </div>\r\n                        {/if}\r\n                        <div class=\"stream-overlay\">\r\n                            <span class=\"timestamp\">{timeStr}</span>\r\n                            <span class=\"cam-label\">{selectedRoom ? `CAM_${String(selectedRoom.room_id).padStart(2,'0')} · ROOM_${selectedRoom.room_id}` : 'NO FEED'}</span>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"room-footer glass\">\r\n                        <div class=\"footer-left\">\r\n                            <span class=\"footer-label\">Current Feed</span>\r\n                            <span class=\"footer-val\">{selectedRoom ? `Room ${selectedRoom.room_id}` : 'None'} {cameraConnected ? `· ${selectedRoom.ip}:${selectedRoom.port}` : '· No camera'}</span>\r\n                        </div>\r\n                        {#if selectedRoom && selectedRoom.p_count >=0}\r\n                             <div class=\"footer-right\">\r\n                                <span class=\"footer-occ-tag\" class:is-occupied={selectedRoom.p_count > 0}>\r\n                                    {selectedRoom.p_count > 0 ? `👥 ${selectedRoom.p_count} OCCUPIED` : '🔘 EMPTY'}\r\n                                </span>\r\n                             </div>\r\n                        {/if}\r\n                    </div>\r\n                </div>\r\n\r\n\r\n\r\n                <div class=\"right-col\">\r\n                    <aside class=\"room-panel glass\" id=\"room-overview-panel\">\r\n                        <h3>Room Overview</h3>\r\n                        <div class=\"room-scroll\">\r\n                            {#if rooms.length === 0}\r\n                                <p class=\"empty-hint\">No room data available.</p>\r\n                            {/if}\r\n                            {#each rooms as room}\r\n                                <div\r\n                                    class=\"room-row\"\r\n                                    class:room-row-active={selectedRoom?.room_id === room.room_id}\r\n                                    on:click={() => selectRoom(room)}\r\n                                    role=\"button\"\r\n                                    tabindex=\"0\"\r\n                                    on:keypress={(e) => e.key === 'Enter' && selectRoom(room)}\r\n                                >\r\n                                    <span class=\"room-id\">Room {room.room_id}</span>\r\n                                    <div class=\"room-right\">\r\n                                        {#if room.p_count > 0}\r\n                                            <span class=\"p-count-badge\">👤 {room.p_count}</span>\r\n                                        {/if}\r\n                                        <span class=\"room-cam-badge\" class:connected={room.ip && room.port}>\r\n                                            {room.ip && room.port ? '● Live' : '○ No Cam'}\r\n                                        </span>\r\n                                        <span class=\"status-dot\" style=\"background:{statusColor(room.status)};box-shadow:0 0 6px {statusColor(room.status)}\"></span>\r\n                                    </div>\r\n                                </div>\r\n                            {/each}\r\n                        </div>\r\n                        <a href=\"/rooms\" class=\"view-all-btn\" id=\"btn-view-all-rooms\">View All Rooms →</a>\r\n                    </aside>\r\n\r\n                    <aside class=\"alerts-panel glass\" id=\"alerts-panel\">\r\n                        <h3>⚡ Alerts</h3>\r\n                        <div class=\"alerts-scroll\">\r\n                            {#if alerts.length === 0}\r\n                                <p class=\"empty-hint\">No recent alerts.</p>\r\n                            {/if}\r\n                            {#each alerts as alert}\r\n                                <div class=\"alert-row alert-{alert.status}\">\r\n                                    <div class=\"alert-left\">\r\n                                        <span class=\"alert-icon\">\r\n                                            {#if alert.status === 'occupied'}🟢{:else if alert.status === 'vacant'}⚫{:else}🟡{/if}\r\n                                        </span>\r\n                                        <div class=\"alert-text\">\r\n                                            <span class=\"alert-label\">Room {alert.room_id}</span>\r\n                                            <span class=\"alert-msg\">{alert.message}</span>\r\n                                        </div>\r\n                                    </div>\r\n                                    <span class=\"alert-time\">{alert.time}</span>\r\n                                </div>\r\n                            {/each}\r\n                        </div>\r\n                    </aside>\r\n                </div>\r\n\r\n\r\n            </div>\r\n        {/if}\r\n    </div>\r\n</div>\r\n\r\n<style>\r\n    @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;600;700&display=swap');\r\n\r\n    :global(body) {\r\n        margin: 0; padding: 0;\r\n        font-family: 'Outfit', sans-serif;\r\n        background: #090b10;\r\n        color: #e2e8f0;\r\n        overflow: hidden;\r\n    }\r\n\r\n    .dashboard-wrapper {\r\n        display: flex;\r\n        height: 100vh;\r\n        width: 100vw;\r\n        overflow: hidden;\r\n    }\r\n\r\n    .main-content {\r\n        flex: 1;\r\n        padding: 2rem 2.5rem;\r\n        overflow-y: auto;\r\n        background: radial-gradient(circle at 80% 10%, rgba(80,250,123,0.04), transparent 50%);\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1.4rem;\r\n    }\r\n\r\n    .loader-wrap {\r\n        flex: 1;\r\n        display: flex;\r\n        flex-direction: column;\r\n        align-items: center;\r\n        justify-content: center;\r\n        gap: 1.5rem;\r\n        color: #64748b;\r\n    }\r\n\r\n    .loader {\r\n        width: 44px; height: 44px;\r\n        border: 3px solid rgba(80,250,123,0.1);\r\n        border-top-color: #50fa7b;\r\n        border-radius: 50%;\r\n        animation: spin 1s linear infinite;\r\n    }\r\n\r\n    @keyframes spin { to { transform: rotate(360deg); } }\r\n\r\n    .page-header {\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: flex-start;\r\n    }\r\n\r\n    .page-header h1 {\r\n        margin: 0;\r\n        font-size: 1.75rem;\r\n        font-weight: 700;\r\n        background: linear-gradient(to right, #fff, #94a3b8);\r\n        -webkit-background-clip: text;\r\n        background-clip: text;\r\n        -webkit-text-fill-color: transparent;\r\n    }\r\n\r\n    .subtitle { margin: 4px 0 0; color: #64748b; font-size: 0.9rem; }\r\n    .header-right { display: flex; align-items: center; gap: 1rem; }\r\n\r\n    .live-badge {\r\n        display: flex;\r\n        align-items: center;\r\n        gap: 8px;\r\n        background: rgba(80,250,123,0.08);\r\n        color: #50fa7b;\r\n        border: 1px solid rgba(80,250,123,0.15);\r\n        padding: 6px 14px;\r\n        border-radius: 20px;\r\n        font-size: 0.8rem;\r\n        font-weight: 600;\r\n    }\r\n\r\n    .dot-live {\r\n        width: 7px; height: 7px;\r\n        border-radius: 50%;\r\n        background: #50fa7b;\r\n        box-shadow: 0 0 8px #50fa7b;\r\n        animation: pulse 2s infinite;\r\n        display: inline-block;\r\n    }\r\n\r\n    @keyframes pulse {\r\n        0%,100% { transform: scale(1); opacity: 1; }\r\n        50%      { transform: scale(1.6); opacity: 0.5; }\r\n    }\r\n\r\n    .top-stats {\r\n        display: flex;\r\n        gap: 1rem;\r\n        align-items: center;\r\n    }\r\n\r\n    .stat-card {\r\n        flex: 1;\r\n        padding: 1rem 1.4rem;\r\n        border-radius: 16px;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 4px;\r\n    }\r\n\r\n    .stat-label { font-size: 0.75rem; color: #64748b; font-weight: 500; }\r\n    .stat-val {\r\n        font-size: 1.6rem;\r\n        font-weight: 700;\r\n        color: #f8fafc;\r\n    }\r\n    .stat-val small { font-size: 0.8rem; color: #94a3b8; font-weight: 400; }\r\n    .stat-val.warning { color: #ffb86c; }\r\n\r\n\r\n\r\n    .dashboard-grid {\r\n        display: grid;\r\n        grid-template-columns: 1fr 280px;\r\n        grid-template-rows: 1fr;\r\n        gap: 1.2rem;\r\n        position: relative;\r\n        flex: 1;\r\n    }\r\n\r\n    .glass {\r\n        background: rgba(18, 21, 32, 0.55);\r\n        backdrop-filter: blur(14px);\r\n        border: 1px solid rgba(255,255,255,0.05);\r\n    }\r\n\r\n    .card {\r\n        padding: 1.4rem;\r\n        border-radius: 20px;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1.2rem;\r\n        min-height: 0;\r\n    }\r\n\r\n    .card-header {\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: center;\r\n    }\r\n    .card-header h3 { margin: 0; font-size: 1rem; color: #fff; font-weight: 600; }\r\n\r\n    .cctv-actions { display: flex; align-items: center; gap: 10px; }\r\n\r\n    .btn-pill {\r\n        background: rgba(139,233,253,0.1);\r\n        color: #8be9fd;\r\n        border: 1px solid rgba(139,233,253,0.2);\r\n        padding: 4px 12px;\r\n        border-radius: 8px;\r\n        font-size: 0.7rem;\r\n        font-weight: 700;\r\n        cursor: pointer;\r\n        transition: all 0.2s;\r\n        font-family: inherit;\r\n    }\r\n    .btn-pill:hover { background: #8be9fd; color: #000; }\r\n\r\n    .btn-pill.is-raw {\r\n        background: rgba(255,184,108,0.1);\r\n        color: #ffb86c;\r\n        border-color: rgba(255,184,108,0.2);\r\n    }\r\n    .btn-pill.is-raw:hover { background: #ffb86c; color: #000; }\r\n\r\n    .badge-rec {\r\n        font-size: 0.65rem;\r\n        font-weight: 800;\r\n        color: #ff5555;\r\n        letter-spacing: 1px;\r\n        animation: blink 1.2s infinite;\r\n    }\r\n    @keyframes blink { 50% { opacity: 0.3; } }\r\n\r\n    .video-wrap {\r\n        position: relative;\r\n        border-radius: 14px;\r\n        overflow: hidden;\r\n        aspect-ratio: 16/9;\r\n        background: #000;\r\n        flex: 1;\r\n    }\r\n    .cctv-feed { width: 100%; height: 100%; object-fit: cover; display: block; }\r\n\r\n    .stream-overlay {\r\n        position: absolute;\r\n        top: 0; left: 0; width: 100%;\r\n        padding: 0.8rem 1rem;\r\n        display: flex;\r\n        justify-content: space-between;\r\n        background: linear-gradient(to bottom, rgba(0,0,0,0.65), transparent);\r\n        font-family: monospace;\r\n        font-size: 0.75rem;\r\n        color: #50fa7b;\r\n        box-sizing: border-box;\r\n    }\r\n\r\n    .room-footer {\r\n        border-radius: 12px;\r\n        padding: 0.7rem 1.2rem;\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: center;\r\n    }\r\n    .footer-left { display: flex; flex-direction: column; gap: 2px; }\r\n    .footer-label { font-size: 0.7rem; color: #64748b; font-weight: 500; text-transform: uppercase; letter-spacing: 0.5px; }\r\n    .footer-val   { font-size: 0.85rem; color: #e2e8f0; font-weight: 600; }\r\n\r\n    .footer-occ-tag {\r\n        font-size: 0.65rem;\r\n        font-weight: 800;\r\n        padding: 4px 10px;\r\n        border-radius: 6px;\r\n        background: rgba(148,163,184,0.1);\r\n        color: #94a3b8;\r\n        border: 1px solid rgba(148,163,184,0.15);\r\n        letter-spacing: 0.5px;\r\n    }\r\n    .footer-occ-tag.is-occupied {\r\n        background: rgba(80,250,123,0.08);\r\n        color: #50fa7b;\r\n        border-color: rgba(80,250,123,0.15);\r\n    }\r\n\r\n\r\n    .right-col {\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1rem;\r\n        overflow-y: auto;\r\n        min-height: 0;\r\n    }\r\n\r\n    .room-panel {\r\n        border-radius: 20px;\r\n        padding: 1.4rem;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1rem;\r\n        overflow: hidden;\r\n        max-height: 20vh;\r\n    }\r\n    .room-panel h3 { margin: 0; font-size: 1rem; color: #fff; }\r\n\r\n    .alerts-panel {\r\n        border-radius: 20px;\r\n        padding: 1.4rem;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1rem;\r\n        overflow: hidden;\r\n        max-height: 45vh;\r\n        margin-top: 0;\r\n    }\r\n    .alerts-panel h3 { margin: 0; font-size: 1rem; color: #fff; }\r\n\r\n    .alerts-scroll {\r\n        flex: 1;\r\n        overflow-y: auto;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 4px;\r\n    }\r\n    .alerts-scroll::-webkit-scrollbar { width: 3px; }\r\n    .alerts-scroll::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 2px; }\r\n\r\n    .alert-row {\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: center;\r\n        padding: 9px 10px;\r\n        border-radius: 10px;\r\n        border-bottom: 1px solid rgba(255,255,255,0.04);\r\n        transition: background 0.15s;\r\n    }\r\n    .alert-row:hover { background: rgba(255,255,255,0.03); }\r\n    .alert-left { display: flex; align-items: flex-start; gap: 8px; }\r\n    .alert-icon { font-size: 0.7rem; margin-top: 2px; }\r\n    .alert-text { display: flex; flex-direction: column; gap: 2px; }\r\n    .alert-label { font-size: 0.82rem; color: #e2e8f0; font-weight: 600; }\r\n    .alert-msg { font-size: 0.72rem; color: #64748b; }\r\n    .alert-time { font-size: 0.68rem; color: #475569; white-space: nowrap; margin-left: 4px; }\r\n\r\n    .room-scroll {\r\n        flex: 1;\r\n        overflow-y: auto;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 4px;\r\n    }\r\n    .room-scroll::-webkit-scrollbar { width: 3px; }\r\n    .room-scroll::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 2px; }\r\n\r\n    .room-row {\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: center;\r\n        padding: 9px 10px;\r\n        border-radius: 10px;\r\n        border-bottom: 1px solid rgba(255,255,255,0.04);\r\n        transition: background 0.15s;\r\n        cursor: pointer;\r\n    }\r\n    .room-row:hover { background: rgba(255,255,255,0.05); }\r\n    .room-row.room-row-active {\r\n        background: rgba(80,250,123,0.08);\r\n        border-color: rgba(80,250,123,0.15);\r\n    }\r\n\r\n    .room-id  { font-size: 0.85rem; color: #e2e8f0; }\r\n    .room-right { display: flex; align-items: center; gap: 8px; }\r\n    .status-dot { width: 7px; height: 7px; border-radius: 50%; flex-shrink: 0; }\r\n\r\n    .room-cam-badge {\r\n        font-size: 0.65rem;\r\n        font-weight: 600;\r\n        color: #475569;\r\n        letter-spacing: 0.3px;\r\n    }\r\n    .room-cam-badge.connected { color: #50fa7b; }\r\n    \r\n    .p-count-badge {\r\n        font-size: 0.75rem;\r\n        background: rgba(139,233,253,0.1);\r\n        color: #8be9fd;\r\n        padding: 2px 6px;\r\n        border-radius: 6px;\r\n        font-weight: 600;\r\n        margin-right: 4px;\r\n    }\r\n\r\n    /* ── No Camera placeholder ── */\r\n    .no-camera {\r\n        width: 100%; height: 100%;\r\n        display: flex;\r\n        flex-direction: column;\r\n        align-items: center;\r\n        justify-content: center;\r\n        gap: 0.5rem;\r\n        background: rgba(9,11,16,0.85);\r\n    }\r\n    .no-cam-icon { font-size: 2.5rem; opacity: 0.4; }\r\n    .no-cam-text { font-size: 1rem; font-weight: 600; color: #64748b; }\r\n    .no-cam-sub  { font-size: 0.75rem; color: #334155; }\r\n\r\n    .empty-hint { color: #475569; font-size: 0.85rem; text-align: center; padding: 2rem 0; }\r\n\r\n    .view-all-btn {\r\n        display: block;\r\n        text-align: center;\r\n        padding: 9px;\r\n        border-radius: 10px;\r\n        background: rgba(80,250,123,0.08);\r\n        color: #50fa7b;\r\n        text-decoration: none;\r\n        font-size: 0.8rem;\r\n        font-weight: 600;\r\n        transition: background 0.2s;\r\n    }\r\n    .view-all-btn:hover { background: rgba(80,250,123,0.15); }\r\n\r\n\r\n\r\n    @media (max-width: 1100px) {\r\n        .dashboard-grid.panel-open { grid-template-columns: 1fr 260px; grid-template-rows: auto auto; }\r\n        :global(.room-panel) { grid-column: 1 / -1; }\r\n    }\r\n</style>","<script>\r\n    import { onMount, onDestroy } from 'svelte';\r\n    import Sidebar from '../components/Sidebar.svelte';\r\n\r\n    let currentUser = null;\r\n    let rooms = [];\r\n    let loading = true;\r\n    let pollInterval;\r\n    let isRefreshing = false;\r\n\r\n    async function fetchRoomsConfig() {\r\n        try {\r\n            isRefreshing = true;\r\n            const roomsRes = await fetch('/api/v1/rooms');\r\n            if (roomsRes.ok) {\r\n                const data = await roomsRes.json();\r\n                rooms = (data.rooms || []).map(r => ({ ...r }));\r\n            }\r\n        } catch (e) {\r\n            console.error('Poll error', e);\r\n        } finally {\r\n            setTimeout(() => { isRefreshing = false; }, 1000);\r\n        }\r\n    }\r\n\r\n    onMount(async () => {\r\n        try {\r\n            const authRes = await fetch('/api/v1/auth/status');\r\n            if (!authRes.ok) { window.location.href = '/login'; return; }\r\n            currentUser = await authRes.json();\r\n\r\n            const roomsRes = await fetch('/api/v1/rooms');\r\n            if (roomsRes.ok) {\r\n                const data = await roomsRes.json();\r\n                rooms = (data.rooms || []).map(r => ({ ...r }));\r\n            }\r\n            pollInterval = setInterval(fetchRoomsConfig, 5000);\r\n        } catch (e) {\r\n            console.error('Rooms init error', e);\r\n        } finally {\r\n            loading = false;\r\n        }\r\n    });\r\n\r\n    onDestroy(() => {\r\n        clearInterval(pollInterval);\r\n    });\r\n\r\n    function statusColor(s = '') {\r\n        const v = s.toLowerCase();\r\n        if (v === 'occupied') return '#50fa7b';\r\n        if (v === 'vacant')   return '#6272a4';\r\n        return '#ffb86c';\r\n    }\r\n\r\n    function statusBg(s = '') {\r\n        const v = s.toLowerCase();\r\n        if (v === 'occupied') return 'rgba(80,250,123,0.08)';\r\n        if (v === 'vacant')   return 'rgba(98,114,164,0.08)';\r\n        return 'rgba(255,184,108,0.08)';\r\n    }\r\n</script>\r\n\r\n<div class=\"page-wrapper\">\r\n    <Sidebar active=\"rooms\" {currentUser} />\r\n\r\n    <div class=\"main-content\">\r\n        {#if loading}\r\n            <div class=\"loader-wrap\">\r\n                <div class=\"loader\"></div>\r\n                <p>Loading room data…</p>\r\n            </div>\r\n        {:else}\r\n            <header class=\"page-header\">\r\n                <div>\r\n                    <h1>Room Details</h1>\r\n                    <p class=\"subtitle\">{rooms.length} rooms monitored — click a card to view usage</p>\r\n                    {#if isRefreshing}\r\n                        <p class=\"subtitle\" style=\"color: #50fa7b; font-weight: bold; margin-top: 8px;\">🔄 Refreshing data...</p>\r\n                    {/if}\r\n                </div>\r\n                <a href=\"/create-room\" class=\"btn-report\" id=\"btn-go-create-room\">➕ Create Room</a>\r\n            </header>\r\n\r\n            <div class=\"rooms-layout\">\r\n                <!-- ── Left: Room Cards Stack ── -->\r\n                <div class=\"rooms-stack\">\r\n                    {#if rooms.length === 0}\r\n                        <div class=\"empty-state glass\">\r\n                            <span>🏠</span>\r\n                            <p>No rooms configured yet.</p>\r\n                        </div>\r\n                    {/if}\r\n\r\n                    {#each rooms as room, i}\r\n                        <div\r\n                            class=\"room-card glass\"\r\n                            id=\"room-card-{room.room_id}\"\r\n                        >\r\n                            <div class=\"room-card-top\">\r\n                                <div class=\"room-id-block\">\r\n                                    <span class=\"room-num\">Room {room.room_id}</span>\r\n                                    <div class=\"status-stack\">\r\n                                        <span\r\n                                            class=\"status-badge\"\r\n                                            style=\"color:{statusColor(room.status)};background:{statusBg(room.status)}\"\r\n                                        >\r\n                                            {room.status}\r\n                                        </span>\r\n                                        {#if room.p_count > 0}\r\n                                            <span class=\"p-count-mini\">👤 {room.p_count} <small>persons</small></span>\r\n                                        {/if}\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"room-meta\">\r\n                                    <div class=\"meta-item\">\r\n                                        <span class=\"meta-label\">Daily Wastage</span>\r\n                                        <span class=\"meta-val\">{room.daily_usage_kwh ?? '—'} <small>kWh</small></span>\r\n                                    </div>\r\n                                    <div class=\"meta-divider\"></div>\r\n                                    <div class=\"meta-item\">\r\n                                        <span class=\"meta-label\">Monthly Wastage</span>\r\n                                        <span class=\"meta-val\">{room.monthly_usage_kwh ?? '—'} <small>kWh</small></span>\r\n                                    </div>\r\n                                    <div class=\"meta-divider\"></div>\r\n                                    <div class=\"meta-item\">\r\n                                        <span class=\"meta-label\">Total Appliances</span>\r\n                                        <span class=\"meta-val\">{room.no_of_appl ?? '—'}</span>\r\n                                    </div>\r\n                                    <div class=\"meta-divider\"></div>\r\n                                    <div class=\"meta-item\">\r\n                                        <span class=\"meta-label\">Running</span>\r\n                                        <span class=\"meta-val meta-running\">6</span>\r\n                                    </div>\r\n                                    <div class=\"meta-divider\"></div>\r\n                                    <div class=\"meta-item\">\r\n                                        <span class=\"meta-label\">Waste Detected</span>\r\n                                        <span class=\"meta-val meta-waste-{(room.status === 'empty' || room.status === 'vacant') && room.current_usage_kw > 0.02 ? 'yes' : 'no'}\">\r\n                                            {(room.status === 'empty' || room.status === 'vacant') && room.current_usage_kw > 0.02 ? 'TRUE' : 'FALSE'}\r\n                                        </span>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"room-actions\">\r\n                                    <span class=\"cam-indicator\" class:cam-live={room.ip && room.port}>\r\n                                        {room.ip && room.port ? '● Camera Live' : '○ No Camera'}\r\n                                    </span>\r\n                                    <a\r\n                                        href=\"/dashboard?room={room.room_id}\"\r\n                                        class=\"btn-view-feed\"\r\n                                        id=\"btn-feed-{room.room_id}\"\r\n                                    >\r\n                                        🎥 View Feed\r\n                                    </a>\r\n                                </div>\r\n\r\n                            </div>\r\n                        </div>\r\n                    {/each}\r\n                </div>\r\n            </div>\r\n        {/if}\r\n    </div>\r\n</div>\r\n\r\n<style>\r\n    @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;600;700&display=swap');\r\n\r\n    :global(body) {\r\n        margin: 0; padding: 0;\r\n        font-family: 'Outfit', sans-serif;\r\n        background: #090b10;\r\n        color: #e2e8f0;\r\n        overflow: hidden;\r\n    }\r\n\r\n    .page-wrapper {\r\n        display: flex;\r\n        height: 100vh;\r\n        width: 100vw;\r\n        overflow: hidden;\r\n    }\r\n\r\n    .main-content {\r\n        flex: 1;\r\n        padding: 2rem 2.5rem;\r\n        overflow-y: auto;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1.5rem;\r\n        background: radial-gradient(circle at 20% 80%, rgba(189,147,249,0.04), transparent 50%);\r\n    }\r\n\r\n    .loader-wrap {\r\n        flex: 1;\r\n        display: flex;\r\n        flex-direction: column;\r\n        align-items: center;\r\n        justify-content: center;\r\n        gap: 1.5rem;\r\n        color: #64748b;\r\n    }\r\n\r\n    .loader {\r\n        width: 44px; height: 44px;\r\n        border: 3px solid rgba(80,250,123,0.1);\r\n        border-top-color: #50fa7b;\r\n        border-radius: 50%;\r\n        animation: spin 1s linear infinite;\r\n    }\r\n\r\n    @keyframes spin { to { transform: rotate(360deg); } }\r\n\r\n    /* ── Header ── */\r\n    .page-header {\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: flex-start;\r\n    }\r\n\r\n    .page-header h1 {\r\n        margin: 0;\r\n        font-size: 1.75rem;\r\n        font-weight: 700;\r\n        background: linear-gradient(to right, #fff, #94a3b8);\r\n        -webkit-background-clip: text;\r\n        background-clip: text;\r\n        -webkit-text-fill-color: transparent;\r\n    }\r\n\r\n    .subtitle { margin: 4px 0 0; color: #64748b; font-size: 0.88rem; }\r\n\r\n    .btn-report {\r\n        background: rgba(80,250,123,0.1);\r\n        color: #50fa7b;\r\n        border: 1px solid rgba(80,250,123,0.2);\r\n        padding: 9px 18px;\r\n        border-radius: 12px;\r\n        text-decoration: none;\r\n        font-size: 0.85rem;\r\n        font-weight: 600;\r\n        transition: all 0.2s;\r\n    }\r\n\r\n    .btn-report:hover { background: rgba(80,250,123,0.18); transform: translateY(-1px); }\r\n\r\n    /* ── Layout ── */\r\n    .rooms-layout {\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1.5rem;\r\n        flex: 1;\r\n        min-height: 0;\r\n    }\r\n\r\n    /* ── Rooms Stack ── */\r\n    .rooms-stack {\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1rem;\r\n        overflow-y: auto;\r\n    }\r\n\r\n    .rooms-stack::-webkit-scrollbar { width: 3px; }\r\n    .rooms-stack::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); }\r\n\r\n    .empty-state {\r\n        border-radius: 20px;\r\n        padding: 3rem;\r\n        text-align: center;\r\n        display: flex;\r\n        flex-direction: column;\r\n        align-items: center;\r\n        gap: 1rem;\r\n        color: #475569;\r\n        font-size: 2rem;\r\n    }\r\n\r\n    .empty-state p { font-size: 0.9rem; margin: 0; }\r\n\r\n    /* ── Room Card ── */\r\n    .glass {\r\n        background: rgba(18,21,32,0.55);\r\n        backdrop-filter: blur(14px);\r\n        border: 1px solid rgba(255,255,255,0.05);\r\n    }\r\n\r\n    .room-card {\r\n        padding: 1.3rem 1.5rem;\r\n        border-radius: 18px;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1rem;\r\n        transition: border-color 0.3s, transform 0.2s;\r\n    }\r\n\r\n    .room-card-top {\r\n        display: flex;\r\n        align-items: center;\r\n        gap: 1.5rem;\r\n        flex-wrap: wrap;\r\n    }\r\n\r\n    .room-id-block { display: flex; flex-direction: column; gap: 5px; min-width: 100px; }\r\n\r\n    .room-num { font-size: 1.1rem; font-weight: 700; color: #f8fafc; }\r\n\r\n    .status-badge {\r\n        display: inline-block;\r\n        padding: 3px 10px;\r\n        border-radius: 8px;\r\n        font-size: 0.7rem;\r\n        font-weight: 700;\r\n        letter-spacing: 0.5px;\r\n    }\r\n\r\n    .room-meta {\r\n        display: flex;\r\n        align-items: center;\r\n        gap: 1rem;\r\n        flex: 1;\r\n    }\r\n\r\n    .meta-item { display: flex; flex-direction: column; gap: 2px; }\r\n    .meta-label { font-size: 0.7rem; color: #64748b; }\r\n    .meta-val { font-size: 1rem; font-weight: 600; color: #e2e8f0; }\r\n    .meta-val small { font-size: 0.7rem; color: #94a3b8; }\r\n    .meta-running { color: #50fa7b; }\r\n    .meta-waste-yes { color: #ff5555; }\r\n    .meta-waste-no  { color: #50fa7b; }\r\n    .meta-divider { width: 1px; height: 30px; background: rgba(255,255,255,0.06); }\r\n\r\n    .room-actions {\r\n        display: flex;\r\n        align-items: center;\r\n        gap: 12px;\r\n        margin-left: auto;\r\n    }\r\n\r\n    .cam-indicator {\r\n        font-size: 0.68rem;\r\n        font-weight: 600;\r\n        color: #475569;\r\n        letter-spacing: 0.3px;\r\n        white-space: nowrap;\r\n    }\r\n    .cam-indicator.cam-live { color: #50fa7b; }\r\n\r\n    .status-stack { display: flex; flex-direction: column; gap: 4px; }\r\n    .p-count-mini {\r\n        font-size: 0.65rem;\r\n        font-weight: 700;\r\n        color: #8be9fd;\r\n        background: rgba(139,233,253,0.06);\r\n        padding: 2px 6px;\r\n        border-radius: 4px;\r\n        width: fit-content;\r\n    }\r\n    .p-count-mini small { font-weight: 400; opacity: 0.7; }\r\n\r\n    .btn-view-feed {\r\n        display: inline-flex;\r\n        align-items: center;\r\n        gap: 5px;\r\n        padding: 7px 14px;\r\n        border-radius: 10px;\r\n        background: rgba(80,250,123,0.08);\r\n        color: #50fa7b;\r\n        border: 1px solid rgba(80,250,123,0.15);\r\n        font-size: 0.78rem;\r\n        font-weight: 600;\r\n        text-decoration: none;\r\n        transition: all 0.2s;\r\n        font-family: inherit;\r\n        white-space: nowrap;\r\n    }\r\n    .btn-view-feed:hover {\r\n        background: rgba(80,250,123,0.16);\r\n        border-color: rgba(80,250,123,0.3);\r\n        transform: translateY(-1px);\r\n    }\r\n</style>\r\n","<script>\n    import { onMount } from 'svelte';\n    import Sidebar from '../components/Sidebar.svelte';\n\n    let currentUser = null;\n    let rooms = [];\n    let loading = true;\n    let searchQuery = '';\n    let selectedRoom = null;\n    let graphMode = 'daily'; // 'daily' | 'monthly'\n\n    $: filteredRooms = rooms.filter(r =>\n        String(r.room_id).toLowerCase().includes(searchQuery.toLowerCase()) ||\n        (r.room_name || '').toLowerCase().includes(searchQuery.toLowerCase())\n    );\n\n    $: if (filteredRooms.length === 1 && searchQuery) {\n        selectedRoom = filteredRooms[0];\n    }\n\n    onMount(async () => {\n        try {\n            const authRes = await fetch('/api/v1/auth/status');\n            if (!authRes.ok) { window.location.href = '/login'; return; }\n            currentUser = await authRes.json();\n\n            const roomsRes = await fetch('/api/v1/rooms');\n            if (roomsRes.ok) {\n                const data = await roomsRes.json();\n                rooms = data.rooms || [];\n            }\n        } catch (e) {\n            console.error('Report init error', e);\n        } finally {\n            loading = false;\n        }\n    });\n\n    function selectRoom(room) {\n        selectedRoom = room;\n        searchQuery = String(room.room_id);\n    }\n\n    function statusColor(s = '') {\n        const v = s.toLowerCase();\n        if (v === 'occupied') return '#50fa7b';\n        if (v === 'vacant')   return '#6272a4';\n        return '#ffb86c';\n    }\n\n    // Build SVG polyline points from bar data\n    function buildPolyline(bars = [], width = 380, height = 120) {\n        if (!bars.length) return '';\n        const max = Math.max(...bars, 1);\n        return bars.map((v, i) => {\n            const x = (i / (bars.length - 1)) * width;\n            const y = height - (v / max) * (height - 10) - 5;\n            return `${x.toFixed(1)},${y.toFixed(1)}`;\n        }).join(' ');\n    }\n\n    function downloadCSV() {\n        if (!selectedRoom) return;\n        const headers = ['Room ID', 'Status', 'Current kW', 'Daily kWh', 'Monthly kWh', 'Floor'];\n        const row = [\n            selectedRoom.room_id,\n            selectedRoom.status,\n            selectedRoom.current_usage_kw ?? '',\n            selectedRoom.daily_usage_kwh ?? '',\n            selectedRoom.monthly_usage_kwh ?? '',\n            selectedRoom.floor ?? '',\n        ];\n        const csv = [headers.join(','), row.join(',')].join('\\n');\n        const blob = new Blob([csv], { type: 'text/csv' });\n        const url  = URL.createObjectURL(blob);\n        const a    = document.createElement('a');\n        a.href     = url;\n        a.download = `room-${selectedRoom.room_id}-report.csv`;\n        a.click();\n        URL.revokeObjectURL(url);\n    }\n\n    $: dailyBars   = selectedRoom?.daily_bars   || [4,6,5,8,7,9,6];\n    $: monthlyBars = selectedRoom?.monthly_bars || [60,75,55,90,80,70,85,65,78,88,72,68];\n    $: activeBars  = graphMode === 'daily' ? dailyBars : monthlyBars;\n    $: barLabels   = graphMode === 'daily'\n        ? ['Mon','Tue','Wed','Thu','Fri','Sat','Sun']\n        : ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];\n    $: polylineGreen = buildPolyline(dailyBars);\n    $: polylinePink  = buildPolyline(monthlyBars.map(v => v * 0.12));\n</script>\n\n<div class=\"page-wrapper\">\n    <Sidebar active=\"report\" {currentUser} />\n\n    <div class=\"main-content\">\n        {#if loading}\n            <div class=\"loader-wrap\">\n                <div class=\"loader\"></div>\n                <p>Loading report data…</p>\n            </div>\n        {:else}\n            <header class=\"page-header\">\n                <div>\n                    <h1>Report Generator</h1>\n                    <p class=\"subtitle\">Search a room and export its energy usage report</p>\n                </div>\n            </header>\n\n            <div class=\"report-grid\">\n                <!-- ── Left Main Column ── -->\n                <div class=\"report-main\">\n\n                    <!-- Search -->\n                    <div class=\"search-card glass\" id=\"search-card\">\n                        <div class=\"search-inner\">\n                            <span class=\"search-icon\">🔍</span>\n                            <input\n                                id=\"room-search\"\n                                type=\"text\"\n                                placeholder=\"Search by room number…\"\n                                bind:value={searchQuery}\n                                autocomplete=\"off\"\n                            />\n                            {#if searchQuery}\n                                <button class=\"clear-btn\" on:click={() => { searchQuery = ''; selectedRoom = null; }}>✕</button>\n                            {/if}\n                        </div>\n                        {#if searchQuery && filteredRooms.length > 1}\n                            <div class=\"search-dropdown\">\n                                {#each filteredRooms.slice(0,6) as room}\n                                    <button class=\"dropdown-item\" on:click={() => selectRoom(room)}>\n                                        <span class=\"dd-id\">Room {room.room_id}</span>\n                                        <span\n                                            class=\"dd-status\"\n                                            style=\"color:{statusColor(room.status)}\"\n                                        >{room.status}</span>\n                                    </button>\n                                {/each}\n                            </div>\n                        {/if}\n                    </div>\n\n                    <!-- Preview Card -->\n                    <div class=\"preview-card glass\" id=\"preview-card\">\n                        {#if selectedRoom}\n                            <div class=\"preview-header\">\n                                <div>\n                                    <span class=\"preview-room-id\">Room {selectedRoom.room_id}</span>\n                                    <span\n                                        class=\"preview-status\"\n                                        style=\"color:{statusColor(selectedRoom.status)}\"\n                                    >{selectedRoom.status}</span>\n                                </div>\n                                <button class=\"btn-csv\" id=\"btn-download-csv\" on:click={downloadCSV}>\n                                    ⬇ Download CSV\n                                </button>\n                            </div>\n\n                            <div class=\"preview-metrics\">\n                                <div class=\"prev-metric\">\n                                    <span class=\"pm-label\">Current Load</span>\n                                    <span class=\"pm-val\">{selectedRoom.current_usage_kw ?? '—'} <small>kW</small></span>\n                                </div>\n                                <div class=\"prev-metric\">\n                                    <span class=\"pm-label\">Daily Usage</span>\n                                    <span class=\"pm-val\">{selectedRoom.daily_usage_kwh ?? '—'} <small>kWh</small></span>\n                                </div>\n                                <div class=\"prev-metric\">\n                                    <span class=\"pm-label\">Monthly Usage</span>\n                                    <span class=\"pm-val\">{selectedRoom.monthly_usage_kwh ?? '—'} <small>kWh</small></span>\n                                </div>\n                                <div class=\"prev-metric\">\n                                    <span class=\"pm-label\">Floor</span>\n                                    <span class=\"pm-val\">{selectedRoom.floor ?? '—'}</span>\n                                </div>\n                            </div>\n                        {:else}\n                            <div class=\"preview-empty\">\n                                <span class=\"empty-icon\">📋</span>\n                                <p>Search and select a room to preview its details</p>\n                            </div>\n                        {/if}\n                    </div>\n\n                    <!-- Graph Card -->\n                    <div class=\"graph-card glass\" id=\"graph-card\">\n                        <div class=\"graph-header\">\n                            <h3>Usage Graph{selectedRoom ? ` — Room ${selectedRoom.room_id}` : ''}</h3>\n                            <div class=\"graph-tabs\">\n                                <button\n                                    class=\"gtab\"\n                                    class:gtab-active={graphMode === 'daily'}\n                                    on:click={() => graphMode = 'daily'}\n                                    id=\"btn-graph-daily\"\n                                >Daily</button>\n                                <button\n                                    class=\"gtab\"\n                                    class:gtab-active={graphMode === 'monthly'}\n                                    on:click={() => graphMode = 'monthly'}\n                                    id=\"btn-graph-monthly\"\n                                >Monthly</button>\n                            </div>\n                        </div>\n\n                        <div class=\"svg-wrap\">\n                            <svg viewBox=\"0 0 380 130\" preserveAspectRatio=\"none\">\n                                <!-- Grid lines -->\n                                {#each [0,1,2,3] as g}\n                                    <line\n                                        x1=\"0\" y1=\"{10 + g*30}\"\n                                        x2=\"380\" y2=\"{10 + g*30}\"\n                                        stroke=\"rgba(255,255,255,0.04)\" stroke-width=\"1\"\n                                    />\n                                {/each}\n\n                                <!-- Area fill (green) -->\n                                {#if graphMode === 'daily'}\n                                    <defs>\n                                        <linearGradient id=\"grad-green\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                                            <stop offset=\"0%\" stop-color=\"#50fa7b\" stop-opacity=\"0.3\"/>\n                                            <stop offset=\"100%\" stop-color=\"#50fa7b\" stop-opacity=\"0\"/>\n                                        </linearGradient>\n                                    </defs>\n                                    <polygon\n                                        points=\"0,125 {polylineGreen} 380,125\"\n                                        fill=\"url(#grad-green)\"\n                                    />\n                                    <polyline\n                                        points={polylineGreen}\n                                        fill=\"none\"\n                                        stroke=\"#50fa7b\"\n                                        stroke-width=\"2\"\n                                        stroke-linecap=\"round\"\n                                        stroke-linejoin=\"round\"\n                                    />\n                                {:else}\n                                    <defs>\n                                        <linearGradient id=\"grad-pink\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                                            <stop offset=\"0%\" stop-color=\"#ff79c6\" stop-opacity=\"0.3\"/>\n                                            <stop offset=\"100%\" stop-color=\"#ff79c6\" stop-opacity=\"0\"/>\n                                        </linearGradient>\n                                    </defs>\n                                    <polygon\n                                        points=\"0,125 {polylinePink} 380,125\"\n                                        fill=\"url(#grad-pink)\"\n                                    />\n                                    <polyline\n                                        points={polylinePink}\n                                        fill=\"none\"\n                                        stroke=\"#ff79c6\"\n                                        stroke-width=\"2\"\n                                        stroke-linecap=\"round\"\n                                        stroke-linejoin=\"round\"\n                                    />\n                                {/if}\n                            </svg>\n\n                            <!-- X-axis labels -->\n                            <div class=\"x-labels\">\n                                {#each barLabels as lbl}\n                                    <span>{lbl}</span>\n                                {/each}\n                            </div>\n                        </div>\n\n                        <!-- Legend -->\n                        <div class=\"graph-legend\">\n                            <span class=\"legend-item\">\n                                <span class=\"legend-dot\" style=\"background:#50fa7b\"></span>\n                                Daily kWh\n                            </span>\n                            <span class=\"legend-item\">\n                                <span class=\"legend-dot\" style=\"background:#ff79c6\"></span>\n                                Monthly kWh\n                            </span>\n                        </div>\n                    </div>\n                </div>\n\n                <!-- ── Right: Room Overview Panel ── -->\n                <aside class=\"room-overview glass\" id=\"report-room-overview\">\n                    <h3>Room Overview</h3>\n                    <div class=\"overview-scroll\">\n                        {#each rooms as room}\n                            <button\n                                class=\"ov-row\"\n                                class:ov-selected={selectedRoom?.room_id === room.room_id}\n                                on:click={() => selectRoom(room)}\n                                id=\"ov-room-{room.room_id}\"\n                            >\n                                <div class=\"ov-left\">\n                                    <span\n                                        class=\"ov-dot\"\n                                        style=\"background:{statusColor(room.status)};box-shadow:0 0 6px {statusColor(room.status)}\"\n                                    ></span>\n                                    <span class=\"ov-name\">Room {room.room_id}</span>\n                                </div>\n                                <div class=\"ov-right\">\n                                    <span class=\"ov-kw\">{room.current_usage_kw ?? '—'} kW</span>\n                                </div>\n                            </button>\n                        {/each}\n                        {#if rooms.length === 0}\n                            <p class=\"empty-hint\">No rooms found.</p>\n                        {/if}\n                    </div>\n                </aside>\n            </div>\n        {/if}\n    </div>\n</div>\n\n<style>\n    @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;600;700&display=swap');\n\n    :global(body) {\n        margin: 0; padding: 0;\n        font-family: 'Outfit', sans-serif;\n        background: #090b10;\n        color: #e2e8f0;\n        overflow: hidden;\n    }\n\n    .page-wrapper {\n        display: flex;\n        height: 100vh;\n        width: 100vw;\n        overflow: hidden;\n    }\n\n    .main-content {\n        flex: 1;\n        padding: 2rem 2.5rem;\n        overflow-y: auto;\n        display: flex;\n        flex-direction: column;\n        gap: 1.5rem;\n        background: radial-gradient(circle at 60% 90%, rgba(255,121,198,0.04), transparent 50%);\n    }\n\n    .loader-wrap {\n        flex: 1;\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        justify-content: center;\n        gap: 1.5rem;\n        color: #64748b;\n    }\n\n    .loader {\n        width: 44px; height: 44px;\n        border: 3px solid rgba(80,250,123,0.1);\n        border-top-color: #50fa7b;\n        border-radius: 50%;\n        animation: spin 1s linear infinite;\n    }\n\n    @keyframes spin { to { transform: rotate(360deg); } }\n\n    .page-header h1 {\n        margin: 0;\n        font-size: 1.75rem;\n        font-weight: 700;\n        background: linear-gradient(to right, #fff, #94a3b8);\n        -webkit-background-clip: text;\n        background-clip: text;\n        -webkit-text-fill-color: transparent;\n    }\n\n    .subtitle { margin: 4px 0 0; color: #64748b; font-size: 0.88rem; }\n\n    /* ── Layout ── */\n    .report-grid {\n        display: grid;\n        grid-template-columns: 1fr 260px;\n        gap: 1.5rem;\n        flex: 1;\n        align-items: start;\n    }\n\n    .report-main { display: flex; flex-direction: column; gap: 1.2rem; }\n\n    /* ── Glass ── */\n    .glass {\n        background: rgba(18,21,32,0.55);\n        backdrop-filter: blur(14px);\n        border: 1px solid rgba(255,255,255,0.05);\n    }\n\n    /* ── Search ── */\n    .search-card {\n        border-radius: 16px;\n        overflow: visible;\n        position: relative;\n    }\n\n    .search-inner {\n        display: flex;\n        align-items: center;\n        gap: 12px;\n        padding: 1rem 1.3rem;\n    }\n\n    .search-icon { font-size: 1rem; opacity: 0.5; }\n\n    .search-inner input {\n        flex: 1;\n        background: none;\n        border: none;\n        color: #f8fafc;\n        font-size: 1rem;\n        font-family: inherit;\n        outline: none;\n    }\n\n    .search-inner input::placeholder { color: #475569; }\n\n    .clear-btn {\n        background: none;\n        border: none;\n        color: #64748b;\n        cursor: pointer;\n        font-size: 0.85rem;\n        padding: 4px 6px;\n        border-radius: 6px;\n        transition: color 0.2s;\n    }\n\n    .clear-btn:hover { color: #ff5555; }\n\n    .search-dropdown {\n        position: absolute;\n        top: 100%;\n        left: 0;\n        right: 0;\n        background: rgba(15,18,28,0.98);\n        border: 1px solid rgba(255,255,255,0.08);\n        border-radius: 0 0 14px 14px;\n        z-index: 100;\n        backdrop-filter: blur(14px);\n        overflow: hidden;\n    }\n\n    .dropdown-item {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        padding: 10px 1.3rem;\n        width: 100%;\n        background: none;\n        border: none;\n        cursor: pointer;\n        font-family: inherit;\n        transition: background 0.15s;\n    }\n\n    .dropdown-item:hover { background: rgba(255,255,255,0.04); }\n\n    .dd-id { font-size: 0.9rem; color: #e2e8f0; }\n    .dd-status { font-size: 0.75rem; font-weight: 600; }\n\n    /* ── Preview Card ── */\n    .preview-card {\n        border-radius: 18px;\n        padding: 1.4rem;\n        min-height: 120px;\n    }\n\n    .preview-header {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        margin-bottom: 1.2rem;\n    }\n\n    .preview-room-id { font-size: 1.3rem; font-weight: 700; color: #f8fafc; margin-right: 10px; }\n    .preview-status  { font-size: 0.8rem; font-weight: 700; }\n\n    .btn-csv {\n        background: rgba(80,250,123,0.12);\n        color: #50fa7b;\n        border: 1px solid rgba(80,250,123,0.22);\n        padding: 8px 18px;\n        border-radius: 10px;\n        font-size: 0.85rem;\n        font-weight: 700;\n        cursor: pointer;\n        font-family: inherit;\n        transition: all 0.2s;\n    }\n\n    .btn-csv:hover { background: #50fa7b; color: #090b10; transform: translateY(-1px); }\n\n    .preview-metrics {\n        display: grid;\n        grid-template-columns: repeat(4, 1fr);\n        gap: 1rem;\n    }\n\n    .prev-metric {\n        display: flex;\n        flex-direction: column;\n        gap: 4px;\n        background: rgba(255,255,255,0.02);\n        padding: 0.8rem 1rem;\n        border-radius: 12px;\n        border: 1px solid rgba(255,255,255,0.04);\n    }\n\n    .pm-label { font-size: 0.7rem; color: #64748b; }\n    .pm-val   { font-size: 1.1rem; font-weight: 700; color: #f8fafc; }\n    .pm-val small { font-size: 0.7rem; color: #94a3b8; font-weight: 400; }\n\n    .preview-empty {\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        justify-content: center;\n        gap: 0.7rem;\n        padding: 2rem;\n        color: #475569;\n    }\n\n    .empty-icon { font-size: 2rem; }\n    .preview-empty p { margin: 0; font-size: 0.85rem; }\n\n    /* ── Graph Card ── */\n    .graph-card {\n        border-radius: 18px;\n        padding: 1.4rem;\n        display: flex;\n        flex-direction: column;\n        gap: 1rem;\n    }\n\n    .graph-header {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n    }\n\n    .graph-header h3 { margin: 0; font-size: 1rem; color: #fff; }\n\n    .graph-tabs { display: flex; gap: 6px; }\n\n    .gtab {\n        background: rgba(255,255,255,0.04);\n        color: #64748b;\n        border: 1px solid rgba(255,255,255,0.06);\n        padding: 5px 14px;\n        border-radius: 8px;\n        font-size: 0.78rem;\n        font-weight: 500;\n        cursor: pointer;\n        font-family: inherit;\n        transition: all 0.2s;\n    }\n\n    .gtab:hover { color: #e2e8f0; }\n    .gtab.gtab-active { background: rgba(80,250,123,0.1); color: #50fa7b; border-color: rgba(80,250,123,0.2); }\n\n    .svg-wrap {\n        display: flex;\n        flex-direction: column;\n        gap: 6px;\n    }\n\n    .svg-wrap svg {\n        width: 100%;\n        height: 130px;\n        padding: 0 2px;\n        border-left: 1px solid rgba(255,255,255,0.06);\n        border-bottom: 1px solid rgba(255,255,255,0.06);\n    }\n\n    .x-labels {\n        display: flex;\n        justify-content: space-between;\n        padding: 0 2px;\n    }\n\n    .x-labels span { font-size: 0.6rem; color: #475569; }\n\n    .graph-legend {\n        display: flex;\n        gap: 1.5rem;\n    }\n\n    .legend-item {\n        display: flex;\n        align-items: center;\n        gap: 6px;\n        font-size: 0.78rem;\n        color: #94a3b8;\n    }\n\n    .legend-dot { width: 8px; height: 8px; border-radius: 50%; }\n\n    /* ── Room Overview Panel ── */\n    .room-overview {\n        border-radius: 20px;\n        padding: 1.4rem;\n        display: flex;\n        flex-direction: column;\n        gap: 1rem;\n        max-height: calc(100vh - 200px);\n        overflow: hidden;\n    }\n\n    .room-overview h3 { margin: 0; font-size: 1rem; color: #fff; }\n\n    .overview-scroll {\n        flex: 1;\n        overflow-y: auto;\n        display: flex;\n        flex-direction: column;\n        gap: 3px;\n    }\n\n    .overview-scroll::-webkit-scrollbar { width: 3px; }\n    .overview-scroll::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); }\n\n    .ov-row {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        padding: 8px 10px;\n        border-radius: 10px;\n        cursor: pointer;\n        background: transparent;\n        border: 1px solid transparent;\n        width: 100%;\n        font-family: inherit;\n        transition: all 0.15s;\n    }\n\n    .ov-row:hover { background: rgba(255,255,255,0.03); }\n    .ov-row.ov-selected { background: rgba(80,250,123,0.08); border-color: rgba(80,250,123,0.15); }\n\n    .ov-left { display: flex; align-items: center; gap: 8px; }\n    .ov-dot  { width: 7px; height: 7px; border-radius: 50%; flex-shrink: 0; }\n    .ov-name { font-size: 0.85rem; color: #e2e8f0; }\n    .ov-kw   { font-size: 0.75rem; color: #64748b; }\n\n    .empty-hint { color: #475569; font-size: 0.85rem; text-align: center; padding: 2rem 0; margin: 0; }\n</style>\n","<script>\r\n    import { onMount } from 'svelte';\r\n\r\n    async function handleLogout() {\r\n        try {\r\n            const response = await fetch('/api/v1/logout', {\r\n                method: 'POST',\r\n                headers: {\r\n                    'Content-Type': 'application/json'\r\n                }\r\n            });\r\n\r\n            if (response.ok) {\r\n                // Redirect to login page after successful logout\r\n                window.location.href = '/login';\r\n            } else {\r\n                const data = await response.json();\r\n                console.error('Logout failed:', data.error);\r\n                window.location.href = '/login';\r\n            }\r\n        } catch (error) {\r\n            console.error('Logout error:', error);\r\n            window.location.href = '/login';\r\n        }\r\n    }\r\n\r\n    onMount(() => {\r\n        // Automatically logout when this component mounts\r\n        handleLogout();\r\n    });\r\n</script>\r\n\r\n<main class=\"logout-container\">\r\n    <div class=\"card\">\r\n        <h1>Watt-Watch</h1>\r\n        <p>Logging you out...</p>\r\n        <div class=\"spinner\"></div>\r\n    </div>\r\n</main>\r\n\r\n<style>\r\n    :global(body) {\r\n        margin: 0;\r\n        font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\r\n        background-color: #0f111a;\r\n        color: white;\r\n    }\r\n\r\n    .logout-container {\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        height: 100vh;\r\n    }\r\n\r\n    .card {\r\n        background: #1a1d27;\r\n        padding: 40px;\r\n        border-radius: 12px;\r\n        text-align: center;\r\n        box-shadow: 0 8px 16px rgba(0, 0, 0, 0.4);\r\n        width: 100%;\r\n        max-width: 380px;\r\n    }\r\n\r\n    h1 {\r\n        margin-top: 0;\r\n        color: #50fa7b;\r\n        margin-bottom: 10px;\r\n    }\r\n\r\n    p {\r\n        color: #a8a8b3;\r\n        margin-bottom: 30px;\r\n    }\r\n\r\n    .spinner {\r\n        border: 4px solid #333;\r\n        border-top: 4px solid #50fa7b;\r\n        border-radius: 50%;\r\n        width: 40px;\r\n        height: 40px;\r\n        animation: spin 1s linear infinite;\r\n        margin: 0 auto;\r\n    }\r\n\r\n    @keyframes spin {\r\n        0% { transform: rotate(0deg); }\r\n        100% { transform: rotate(360deg); }\r\n    }\r\n</style>\r\n","<script>\n    import { onMount } from 'svelte';\n    import Sidebar from '../components/Sidebar.svelte';\n\n    let currentUser = null;\n    let loading = false;\n    let errorMsg = '';\n\n    // Form state\n    let ip = '';\n    let port = '';\n    let zone_count = 1;\n    let appliances = [\n        { type: '', wattage: '', zone: '1' }\n    ];\n\n    onMount(async () => {\n        try {\n            const authRes = await fetch('/api/v1/auth/status');\n            if (!authRes.ok) { window.location.href = '/login'; return; }\n            currentUser = await authRes.json();\n        } catch (e) {\n            console.error('Auth check error', e);\n        }\n    });\n\n    function addAppliance() {\n        appliances = [...appliances, { type: '', wattage: '', zone: '1' }];\n    }\n\n    function removeAppliance(index) {\n        if (appliances.length > 1) {\n            appliances = appliances.filter((_, i) => i !== index);\n        }\n    }\n\n    async function createRoom(e) {\n        e.preventDefault();\n        loading = true;\n        errorMsg = '';\n\n        // Validation\n        if (!zone_count || zone_count < 1) {\n            errorMsg = \"Zone count must be at least 1.\";\n            loading = false;\n            return;\n        }\n\n        for (let i = 0; i < appliances.length; i++) {\n            const a = appliances[i];\n            if (!a.type || !a.wattage || !a.zone) {\n                errorMsg = `Please fill out all fields for appliance ${i + 1}.`;\n                loading = false;\n                return;\n            }\n        }\n\n        const payload = {\n            no_of_appl: appliances.length,\n            zone_count: Number(zone_count),\n            appl: appliances.map(a => ({\n                type: a.type,\n                wattage: Number(a.wattage),\n                zone: a.zone\n            })),\n            ip: ip.trim() || null,\n            port: port ? Number(port) : null\n        };\n\n        try {\n            const res = await fetch('/api/v1/add_room', {\n                method: 'POST',\n                headers: { 'Content-Type': 'application/json' },\n                body: JSON.stringify(payload)\n            });\n            if (res.ok) {\n                // Redirect user back to rooms list\n                window.location.href = '/rooms';\n            } else {\n                const data = await res.json();\n                errorMsg = data.error || 'Failed to create room';\n            }\n        } catch (err) {\n            console.error(err);\n            errorMsg = 'Network error while creating room.';\n        } finally {\n            loading = false;\n        }\n    }\n</script>\n\n<div class=\"page-wrapper\">\n    <Sidebar active=\"rooms\" {currentUser} />\n\n    <div class=\"main-content\">\n        <header class=\"page-header\">\n            <div>\n                <h1>Create New Room</h1>\n                <p class=\"subtitle\">Set up configuration and appliances for a new room.</p>\n            </div>\n            <a href=\"/rooms\" class=\"btn-back\">⬅ Back to Rooms</a>\n        </header>\n\n        <div class=\"glass form-container\">\n            <form on:submit={createRoom}>\n                \n                {#if errorMsg}\n                    <div class=\"error-banner\">{errorMsg}</div>\n                {/if}\n\n                <div class=\"form-row\">\n                    <div class=\"form-group flex-1\">\n                        <label for=\"ip\">Camera IP (Optional)</label>\n                        <input type=\"text\" id=\"ip\" bind:value={ip} placeholder=\"e.g. 192.168.0.10\" />\n                    </div>\n                    <div class=\"form-group flex-1\">\n                        <label for=\"port\">Camera Port (Optional)</label>\n                        <input type=\"number\" id=\"port\" bind:value={port} placeholder=\"e.g. 5000\" />\n                    </div>\n                </div>\n\n                <div class=\"form-group\" style=\"max-width: 250px;\">\n                    <label for=\"zone_count\">Total Zones</label>\n                    <input type=\"number\" id=\"zone_count\" bind:value={zone_count} min=\"1\" required />\n                </div>\n\n                <div class=\"appliances-section\">\n                    <div class=\"section-header\">\n                        <h3>Appliances ({appliances.length})</h3>\n                        <button type=\"button\" class=\"btn-add\" on:click={addAppliance}>+ Add Appliance</button>\n                    </div>\n\n                    <div class=\"appliances-list\">\n                        {#each appliances as app, i}\n                            <div class=\"appliance-row\">\n                                <span class=\"app-num\">{i + 1}.</span>\n                                <div class=\"form-group inline\">\n                                    <label>Type</label>\n                                    <input type=\"text\" bind:value={app.type} placeholder=\"e.g. AC, Light\" required />\n                                </div>\n                                <div class=\"form-group inline\">\n                                    <label>Wattage (W)</label>\n                                    <input type=\"number\" bind:value={app.wattage} placeholder=\"e.g. 1500\" required />\n                                </div>\n                                <div class=\"form-group inline sm\">\n                                    <label>Zone</label>\n                                    <input type=\"text\" bind:value={app.zone} placeholder=\"e.g. 1\" required />\n                                </div>\n                                {#if appliances.length > 1}\n                                    <button type=\"button\" class=\"btn-remove\" on:click={() => removeAppliance(i)}>✕</button>\n                                {/if}\n                            </div>\n                        {/each}\n                    </div>\n                </div>\n\n                <div class=\"form-actions\">\n                    <button type=\"submit\" class=\"btn-submit\" disabled={loading}>\n                        {loading ? 'Creating...' : 'Create Room'}\n                    </button>\n                </div>\n            </form>\n        </div>\n    </div>\n</div>\n\n<style>\n    @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;600;700&display=swap');\n\n    :global(body) {\n        margin: 0; padding: 0;\n        font-family: 'Outfit', sans-serif;\n        background: #090b10;\n        color: #e2e8f0;\n        overflow: hidden;\n    }\n\n    .page-wrapper {\n        display: flex;\n        height: 100vh;\n        width: 100vw;\n        overflow: hidden;\n    }\n\n    .main-content {\n        flex: 1;\n        padding: 2rem 2.5rem;\n        overflow-y: auto;\n        display: flex;\n        flex-direction: column;\n        gap: 2rem;\n        background: radial-gradient(circle at 20% 80%, rgba(189,147,249,0.04), transparent 50%);\n    }\n\n    .main-content::-webkit-scrollbar { width: 5px; }\n    .main-content::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 4px; }\n\n    .page-header {\n        display: flex;\n        justify-content: space-between;\n        align-items: flex-start;\n    }\n\n    .page-header h1 {\n        margin: 0;\n        font-size: 1.75rem;\n        font-weight: 700;\n        background: linear-gradient(to right, #fff, #94a3b8);\n        -webkit-background-clip: text;\n        background-clip: text;\n        -webkit-text-fill-color: transparent;\n    }\n\n    .subtitle { margin: 4px 0 0; color: #64748b; font-size: 0.88rem; }\n\n    .btn-back {\n        background: rgba(98,114,164,0.1);\n        color: #8be9fd;\n        border: 1px solid rgba(98,114,164,0.3);\n        padding: 9px 18px;\n        border-radius: 12px;\n        text-decoration: none;\n        font-size: 0.85rem;\n        font-weight: 600;\n        transition: all 0.2s;\n    }\n    .btn-back:hover { background: rgba(98,114,164,0.2); transform: translateY(-1px); }\n\n    .glass {\n        background: rgba(18,21,32,0.55);\n        backdrop-filter: blur(14px);\n        border: 1px solid rgba(255,255,255,0.05);\n    }\n\n    .form-container {\n        padding: 2.5rem;\n        border-radius: 18px;\n        max-width: 800px;\n    }\n\n    .error-banner {\n        background: rgba(255, 85, 85, 0.1);\n        color: #ff5555;\n        border: 1px solid rgba(255, 85, 85, 0.3);\n        padding: 12px;\n        border-radius: 10px;\n        margin-bottom: 1.5rem;\n        font-size: 0.9rem;\n        font-weight: 600;\n        text-align: center;\n    }\n\n    .form-row {\n        display: flex;\n        gap: 1.5rem;\n        flex-wrap: wrap;\n    }\n    .flex-1 { flex: 1; min-width: 200px; }\n\n    .form-group {\n        display: flex;\n        flex-direction: column;\n        gap: 8px;\n        margin-bottom: 1.5rem;\n    }\n    \n    .form-group.inline { margin-bottom: 0; flex: 1; }\n    .form-group.inline.sm { flex: 0.5; }\n    \n    label {\n        font-size: 0.85rem;\n        font-weight: 600;\n        color: #94a3b8;\n    }\n\n    input[type=\"text\"], input[type=\"number\"] {\n        padding: 12px 16px;\n        border-radius: 10px;\n        background: rgba(15,23,42,0.6);\n        border: 1px solid rgba(255,255,255,0.1);\n        color: #f8fafc;\n        font-family: inherit;\n        font-size: 0.95rem;\n        transition: border-color 0.2s;\n    }\n    input[type=\"text\"]:focus, input[type=\"number\"]:focus {\n        outline: none;\n        border-color: #50fa7b;\n    }\n\n    .appliances-section {\n        margin-top: 2rem;\n        border-top: 1px solid rgba(255,255,255,0.06);\n        padding-top: 1.5rem;\n    }\n\n    .section-header {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        margin-bottom: 1.5rem;\n    }\n\n    .section-header h3 { margin: 0; font-size: 1.2rem; color: #f8fafc; }\n\n    .btn-add {\n        background: rgba(139, 233, 253, 0.1);\n        color: #8be9fd;\n        border: 1px solid rgba(139, 233, 253, 0.2);\n        padding: 6px 12px;\n        border-radius: 8px;\n        font-size: 0.8rem;\n        font-weight: 600;\n        cursor: pointer;\